      \"key_fields\": {\"employee_id\": \"E0009\", \"amount\": 5100, \"expense_date\": \"2025-04-10\", \"expense_type\": \"travel_lodging\", \"invoice_no\": \"FP2025X0004206\", \"approval_tier\": \"AR-02\"}
    },
    {
      \"record_id\": \"R004213\",
