      \"effective_date\": \"2025-01-01\"
    },
    {
      \"doc_id\": \"03_authorization_management.md\",
      \"clause\": \"附件二 AR-02/AR-03\",
      \"content\": \"AR-02: ≥3000且<10000 → 部门经理+财务复核; AR-03: ≥10000且<50000 → 部门总经理\",
      \"effective_date\": \"2025-01-01\"
    }
  ],
  \"analysis\": {
    \"date_window\": \"2025-04-10 至 2025-04-15 (5天 ≤ 7天)\",
    \"combined_amount\": 10200.00,
    \"individual_amounts\": [5100.00, 5100.00],
    \"individual_tiers\": [\"AR-02\", \"AR-02\"],
    \"combined_tier\": \"AR-03\",
    \"higher_approval_required\": \"部门总经理\",
    \"actual_approval\": \"部门经理 (E0009自审批)\",
    \"violation\": \"合计10200元达到AR-03线(≥10000)，应经部门总经理审批，实际仅经部门经理审批\"
  },
  \"coverage_status\": \"complete\"
}
EOF
echo \"evidence_matrix.json saved\""

